#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    ll n;    cin >> n;    ll maxi_bus=0;    ll mini_bus=0;    if(n%2==0 && n>=4){        maxi_bus = floor(n/4);        mini_bus = ceil(n/6.0);     }    else{        cout<<-1<<"\n";        return;    }    cout<<mini_bus<<" "<<maxi_bus<<"\n";        } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}